OFFICIAL_LOBBY_BLUEPRINTS = LobbyDefaults.OFFICIAL_BLUEPRINTS


def _normalize_lobby_kind(raw_kind: str) -> str:
    kind = (raw_kind or "").strip().lower()
    if kind in {LobbyDefaults.KIND_OFFICIAL, LobbyDefaults.KIND_CUSTOM, LobbyDefaults.KIND_ALL}:
        return kind
    raise HTTPException(status_code=HttpStatus.BAD_REQUEST, detail="Invalid lobby kind filter.")


def _is_official_lobby(lobby: Lobby) -> bool:
    return (lobby.lobby_kind or LobbyDefaults.KIND_CUSTOM).strip().lower() == LobbyDefaults.KIND_OFFICIAL


def _upsert_official_lobbies() -> None:
    for blueprint in OFFICIAL_LOBBY_BLUEPRINTS:
        Lobby.upsert_official(
            official_key=blueprint["official_key"],
            lobby_name=blueprint["lobby_name"],
            user_capacity=blueprint["user_capacity"],
            server_region=blueprint["server_region"],
            server_description=blueprint["server_description"],
        )


def _normalize_match_token(raw: str) -> str:
    normalized = (raw or "").strip().lower().replace("-", " ").replace("_", " ")
    return " ".join(normalized.split())


def _materialize_assignment(lobby: Lobby, assignment: dict[str, Any]) -> dict[str, str]:
    default_region = (lobby.server_region or "").strip() or LobbyDefaults.UNKNOWN_REGION
    return {
        "game_server_id": str(assignment.get("game_server_id") or "").strip(),
        "game_region": str(assignment.get("region") or "").strip() or default_region,
        "game_ws_base_url": str(assignment.get("game_ws_base_url") or "").strip(),
        "chat_ws_base_url": str(assignment.get("chat_ws_base_url") or "").strip(),
    }


def _official_keys() -> list[str]:
    return [str(blueprint["official_key"]) for blueprint in OFFICIAL_LOBBY_BLUEPRINTS]


def _normalize_official_keys(raw_keys: Any) -> list[str]:
    if not isinstance(raw_keys, list):
        return []
    return [str(key).strip() for key in raw_keys if str(key).strip()]


def _legacy_registry_entries_from_config() -> list[dict[str, Any]]:
    raw = (get_app_config().GAME_SERVER_REGISTRY_JSON or "").strip()
    if not raw:
        return []

    try:
        parsed = json.loads(raw)
    except Exception:
        return []

    if isinstance(parsed, dict):
        raw_entries = []
        for server_id, value in parsed.items():
            if not isinstance(value, dict):
                continue
            entry = dict(value)
            entry.setdefault("server_id", server_id)
            raw_entries.append(entry)
    elif isinstance(parsed, list):
        raw_entries = [entry for entry in parsed if isinstance(entry, dict)]
    else:
        return []

    entries: list[dict[str, Any]] = []
    for raw_entry in raw_entries:
        status = str(raw_entry.get("status") or raw_entry.get("health") or "online").strip().lower()
        if status not in {"online", "healthy", "ready"}:
            continue

        game_ws_base_url = str(
            raw_entry.get("game_ws_base_url")
            or raw_entry.get("gameWsBaseUrl")
            or raw_entry.get("game_ws_url")
            or ""
        ).strip()
        if not game_ws_base_url:
            continue

        chat_ws_base_url = str(
            raw_entry.get("chat_ws_base_url")
            or raw_entry.get("chatWsBaseUrl")
            or raw_entry.get("chat_ws_url")
            or get_app_config().CHAT_WS_PUBLIC_BASE_URL
            or ""
        ).strip()
        if not chat_ws_base_url:
            continue

        entries.append(
            {
                "game_server_id": str(
                    raw_entry.get("game_server_id")
                    or raw_entry.get("server_id")
                    or raw_entry.get("serverId")
                    or raw_entry.get("id")
                    or get_app_config().DEFAULT_GAME_SERVER_ID
                ).strip(),
                "region": str(
                    raw_entry.get("region")
                    or raw_entry.get("game_region")
                    or raw_entry.get("gameRegion")
                    or get_app_config().DEFAULT_GAME_SERVER_REGION
                ).strip(),
                "official_keys": _normalize_official_keys(
                    raw_entry.get("official_keys")
                    or raw_entry.get("officialKeys")
                    or raw_entry.get("allowed_official_keys")
                ),
                "game_ws_base_url": game_ws_base_url,
                "chat_ws_base_url": chat_ws_base_url,
            }
        )
    return entries


def _default_route_assignment() -> dict[str, Any] | None:
    cfg = get_app_config()
    game_ws_base_url = (cfg.GAME_WS_PUBLIC_BASE_URL or cfg.BACKEND_PUBLIC_BASE_URL or "").strip()
    chat_ws_base_url = (cfg.CHAT_WS_PUBLIC_BASE_URL or cfg.BACKEND_PUBLIC_BASE_URL or "").strip()
    if not game_ws_base_url or not chat_ws_base_url:
        return None

    return {
        "game_server_id": (cfg.DEFAULT_GAME_SERVER_ID or "").strip(),
        "region": (cfg.DEFAULT_GAME_SERVER_REGION or "").strip(),
        "official_keys": _official_keys(),
        "game_ws_base_url": game_ws_base_url,
        "chat_ws_base_url": chat_ws_base_url,
    }


def _fallback_route_assignments() -> list[dict[str, Any]]:
    configured_entries = _legacy_registry_entries_from_config()
    if configured_entries:
        return configured_entries

    default_assignment = _default_route_assignment()
    return [default_assignment] if default_assignment is not None else []


def _registry_candidate(entry: GameServerRegistry) -> dict[str, Any]:
    return {
        "game_server_id": entry.server_id,
        "region": entry.region,
        "official_keys": entry.official_keys,
        "game_ws_base_url": entry.game_ws_base_url,
        "chat_ws_base_url": entry.chat_ws_base_url,
    }


def _select_assignment_from_candidates(lobby: Lobby, candidates: list[dict[str, Any]]) -> dict[str, str] | None:
    if not candidates:
        return None
    lobby_official_key = (lobby.official_key or "").strip().lower()
    lobby_region_token = _normalize_match_token(lobby.server_region or "")

    for candidate in candidates:
        entry_official_keys = [
            str(key).strip().lower()
            for key in (candidate.get("official_keys") or [])
            if str(key).strip()
        ]
        if lobby_official_key and lobby_official_key in entry_official_keys:
            return _materialize_assignment(lobby, candidate)

    for candidate in candidates:
        entry_region_token = _normalize_match_token(str(candidate.get("region") or ""))
        if lobby_region_token and entry_region_token and lobby_region_token == entry_region_token:
            return _materialize_assignment(lobby, candidate)

    return _materialize_assignment(lobby, candidates[0])


def _select_game_server_assignment(lobby: Lobby) -> dict[str, str] | None:
    healthy_registry = GameServerRegistry.list_healthy()
    if healthy_registry:
        return _select_assignment_from_candidates(
            lobby,
            [_registry_candidate(entry) for entry in healthy_registry],
        )

    return _select_assignment_from_candidates(lobby, _fallback_route_assignments())


def _ensure_lobby_routing_assignment(lobby: Lobby) -> Lobby | None:
    selected = _select_game_server_assignment(lobby)
    if selected is None:
        return None

    updated = Lobby.update_routing_assignment(
        lobby.id or "",
        game_server_id=selected["game_server_id"],
        game_region=selected["game_region"],
        game_ws_base_url=selected["game_ws_base_url"],
        chat_ws_base_url=selected["chat_ws_base_url"],
    )
    return updated


def _build_assigned_lobby_ws_urls(lobby: Lobby) -> dict[str, str]:
    encoded_lobby_id = quote(lobby.id or "", safe="")
    game_ws_base = (lobby.assigned_game_ws_base_url or "").strip()
    chat_ws_base = (lobby.assigned_chat_ws_base_url or "").strip()
    if not game_ws_base or not chat_ws_base:
        raise HTTPException(
